const PROCESSING_FEE = 5;

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: { op: "quote"; items: unknown[] }[];
};

export const run = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => {
    if (step.items.length === 0) return { premium: PROCESSING_FEE };
    return { premium: 115 };
  });
  return { results };
};

