const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};
type QuoteResult = { premium: number };

const quotePremium = (step: QuoteStep): QuoteResult => {
  if (step.items.length === 0) return { premium: PROCESSING_FEE };
  const itemBase = BASE_PREMIUMS[step.items[0].type];
  const withFirstInsurance = itemBase * (1 + FIRST_INSURANCE_SURCHARGE);
  return { premium: Math.ceil(withFirstInsurance) + PROCESSING_FEE };
};

export const run = (scenario: Scenario): { results: QuoteResult[] } => {
  return { results: scenario.steps.map(quotePremium) };
};

