  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only, not insurance sum");
  it.todo("two swords → insurance sum 2000 G, cap 4000 G");

  // --- Claims: standard reimbursement (no special clauses) ---
  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 − 100 deductible)");
  it.todo("rune (250 G), damage 200 → payout 100 (200 − 100 deductible; no enchantment/material on rune)");

  // --- Claims: enchantment threshold ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (high-enchant 50% then deductible: 500 − 100)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon: full then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (only high-enchant; 50% then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack: sword damage 500 + amulet damage 300 → payout 600 (deductible per item: (500−100)+(300−100))");

  // --- Multiple items of same type ---
  it.todo("two swords damaged → each treated as separate damage with its own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");

  // --- Cap exhaustion across successive claims ---
  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");

  // --- Rounding ---
  it.todo("premium calculation that yields 197.5 → final 198 (rounded up)");
  it.todo("payout calculation that yields 350.5 → final 350 (rounded down)");

  // --- Edge cases / errors ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with stderr message");
  it.todo("claim damages an item not in policy (e.g. amulet damaged when only sword insured) → CLI exits non-zero");
  it.todo("claim damages an item with unknown type → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");

  // --- Integration examples ---
  it.todo("newcomer with cursed steel sword (enchantment 3): 100 + 50 + 10 + 5 = 165 G");
  it.todo("3-year customer's second quote with cursed steel sword (enchantment 7): 100 + 50 + 30 − 20 + 10 − 15 + 5 = 160 G");
});

describe("MHPCO CLI", () => {
  it.todo("CLI reads JSON scenario from stdin and writes results JSON to stdout");
});

