const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};
type QuoteResult = { premium: number };

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type];
  return base + base * FIRST_INSURANCE_SURCHARGE;
};

const quotePremium = (step: QuoteStep): QuoteResult => {
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
};

export const run = (scenario: Scenario): { results: QuoteResult[] } => {
  return { results: scenario.steps.map(quotePremium) };
};

