import { describe, it, expect } from "vitest";
import { run } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list yields premium 5 G (only the processing fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Single main items at base premium (newcomer, first contract scenario adds first-insurance surcharge per-item; use plain config: years=0, with no prior contract) ---
  // We start with simpler cases: a long-standing customer (≥2 yrs) on a follow-up contract — but the simplest is one main item alone.
  // Use single-item, plain (no curse, no high enchantment) to test base premiums in isolation; modifiers will be tested in dedicated cases below.

  it("single sword (plain) for newcomer → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (plain) for newcomer → 60 + 6 + 5 = 71 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff (plain) for newcomer → 80 + 8 + 5 = 93 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "oak", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion (plain) for newcomer → 40 + 4 + 5 = 49 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Components: per-unit and block discount ---
  it("2 runes → 50 G base premium (no block) → total 60 G with first-insurance and fee", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it.todo("3 runes → 60 G base premium (block of 3 alike)");
  it.todo("4 runes → 100 G base premium (no block — needs exactly 3)");
  it.todo("7 runes → 175 G base premium (no blocks applied to leftover groupings beyond 3-alike rule per spec example)");

  // --- "Alike" components clarification ---
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Modifier scope on multi-item policy ---
  it.todo("cursed sword + plain amulet → policy base 160 G; curse adds 50 G (on sword base) → 210 G before policy modifiers and fee");

  // --- Modifier thresholds ---
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("cursed sword with enchantment 5 → both surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // --- Insurance value sums & cap ---
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only, not insurance sum");
  it.todo("two swords → insurance sum 2000 G, cap 4000 G");

  // --- Claims: standard reimbursement (no special clauses) ---
  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 − 100 deductible)");
  it.todo("rune (250 G), damage 200 → payout 100 (200 − 100 deductible; no enchantment/material on rune)");

  // --- Claims: enchantment threshold ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (high-enchant 50% then deductible: 500 − 100)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon: full then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (only high-enchant; 50% then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack: sword damage 500 + amulet damage 300 → payout 600 (deductible per item: (500−100)+(300−100))");

  // --- Multiple items of same type ---
  it.todo("two swords damaged → each treated as separate damage with its own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");

  // --- Cap exhaustion across successive claims ---
  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");

  // --- Rounding ---
  it.todo("premium calculation that yields 197.5 → final 198 (rounded up)");
  it.todo("payout calculation that yields 350.5 → final 350 (rounded down)");

  // --- Edge cases / errors ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with stderr message");
  it.todo("claim damages an item not in policy (e.g. amulet damaged when only sword insured) → CLI exits non-zero");
  it.todo("claim damages an item with unknown type → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");

  // --- Integration examples ---
  it.todo("newcomer with cursed steel sword (enchantment 3): 100 + 50 + 10 + 5 = 165 G");
  it.todo("3-year customer's second quote with cursed steel sword (enchantment 7): 100 + 50 + 30 − 20 + 10 − 15 + 5 = 160 G");
});

describe("MHPCO CLI", () => {
  it.todo("CLI reads JSON scenario from stdin and writes results JSON to stdout");
});

