type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_SURCHARGE_RATE;

const itemPremium = (item: Item): number => withFirstInsurance(BASE_PREMIUMS[item.type]);

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_BASE_PREMIUM = 60;

const isBlockOfThreeAlike = (items: Item[]): boolean =>
  items.length === 3 && items.every((i) => i.type === items[0].type);

const componentsBase = (components: Item[]): number =>
  isBlockOfThreeAlike(components)
    ? BLOCK_BASE_PREMIUM
    : components.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);

const quotePremium = (step: QuoteStep): QuoteResult => {
  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
  const nonComponents = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
  const nonComponentTotal = nonComponents.reduce((sum, item) => sum + itemPremium(item), 0);
  const componentTotal = withFirstInsurance(componentsBase(components));
  return { premium: Math.ceil(nonComponentTotal + componentTotal + PROCESSING_FEE) };
};

export const run = (scenario: Scenario): { results: QuoteResult[] } => {
  return { results: scenario.steps.map(quotePremium) };
};

