type Item = { type: string; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = {
  customer: Customer;
  steps: QuoteStep[];
};
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_SURCHARGE_RATE;

const CURSE_SURCHARGE_RATE = 0.5;

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type];
  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
  return withFirstInsurance(base) + curse;
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const groupBasePremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];

const componentsBase = (components: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(components)) {
    total += groupBasePremium(type, count);
  }
  return total;
};

const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS = 2;

const quotePremium = (step: QuoteStep, customer: Customer): QuoteResult => {
  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
  const nonComponents = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
  const nonComponentTotal = nonComponents.reduce((sum, item) => sum + itemPremium(item), 0);
  const componentBase = componentsBase(components);
  const componentTotal = withFirstInsurance(componentBase);
  const nonComponentBase = nonComponents.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const policyBase = nonComponentBase + componentBase;
  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
  return { premium: Math.ceil(nonComponentTotal + componentTotal - loyalty + PROCESSING_FEE) };
};

export const run = (scenario: Scenario): { results: QuoteResult[] } => {
  return { results: scenario.steps.map((step) => quotePremium(step, scenario.customer)) };
};

