const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
  const cap = insuranceSum(policyItems) * CAP_MULTIPLIER;
  const payout = step.incident.damages.reduce(
    (sum, d) => sum + Math.max(0, d.amount - DEDUCTIBLE),
    0,
  );
  return { payout: Math.floor(payout), remainingCap: cap - payout };
};

export const run = (scenario: Scenario): { results: StepResult[] } => {
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push(quotePremium(step, scenario.customer));
    } else {
      const policyStep = scenario.steps[step.policy] as QuoteStep;
      results.push(claimResult(step, policyStep.items));
    }
  }
  return { results };
};

