export const run = (scenario: Scenario): { results: StepResult[] } => {
  const results: StepResult[] = [];
  const remainingCapByPolicy = new Map<number, number>();
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push(quotePremium(step, scenario.customer));
    } else {
      const policyItems = policyItemsFor(step, scenario.steps);
      const available =
        remainingCapByPolicy.get(step.policy) ?? insuranceSum(policyItems) * CAP_MULTIPLIER;
      const result = claimResult(step, policyItems, available);
      remainingCapByPolicy.set(step.policy, result.remainingCap);
      results.push(result);
    }
  }
  return { results };
};

